import { getImageUrl } from '../services/api';
import { useNavigate } from 'react-router-dom';
import { CreatePlaylistModal } from '../components/CreatePlaylistModal';
import { motion } from 'framer-motion';

const containerVariants = {
  hidden: { opacity: 0 },
  visible: {
    opacity: 1,
    transition: {
      staggerChildren: 0.08,
      delayChildren: 0.1
    }
  }
};

const itemVariants = {
  hidden: { opacity: 0, x: -20 },
  visible: { 
    opacity: 1, 
    x: 0,
    transition: {
        type: "spring",
        stiffness: 260,
        damping: 20
    }
  }
};

export const Library: React.FC = () => {
  const { likedSongs, userPlaylists, currentUser, isOfflineMode, downloadedSongIds } = usePlayerStore();
  const navigate = useNavigate();
  const [filter, setFilter] = useState<'All' | 'Playlists' | 'Artists' | 'Downloaded'>('All');
  const [isModalOpen, setIsModalOpen] = useState(false);

  // Filter Logic
  const filteredPlaylists = userPlaylists.filter(() => {
     if (isOfflineMode || filter === 'Downloaded') {
         return true; 
     }
     return true;
  });

  const downloadedLikedSongsCount = likedSongs.filter(s => downloadedSongIds.includes(s.id)).length;

  const FilterChip = ({ label }: { label: string }) => (
      <motion.button 
        whileHover={{ scale: 1.05 }}
        whileTap={{ scale: 0.95 }}
        onClick={() => setFilter(label as any)}
        className={`px-4 py-1.5 rounded-full text-xs font-medium border border-transparent transition-colors ${filter === label ? 'bg-white text-black' : 'bg-[#2A2A2A] text-white hover:bg-[#3E3E3E]'}`}
      >
          {label}
      </motion.button>
  );

  const handleProfileClick = () => {
    if (currentUser) {
        navigate('/profile');
    } else {
        navigate('/login');
    }
  };

  return (
    <div className="min-h-full pb-32 bg-[#121212] pt-4 px-4">

      {/* Header */}
      <div className="flex items-center justify-between mb-4 sticky top-0 bg-[#121212] z-20 py-2">
          <div className="flex items-center gap-3">
              <motion.div 
                 whileHover={{ scale: 1.1 }}
                 whileTap={{ scale: 0.9 }}
                 onClick={handleProfileClick}
                 className="w-8 h-8 rounded-full bg-white flex items-center justify-center font-bold text-black text-xs cursor-pointer overflow-hidden"
              >
                  {currentUser && currentUser.image ? (
                     <img src={currentUser.image} alt="Profile" className="w-full h-full object-cover" />
                  ) : (
                     <span className="font-bold">{currentUser ? currentUser.name.charAt(0).toUpperCase() : <UserCircle size={20} />}</span>
                  )}
              </motion.div>
              <h1 className="text-2xl font-bold text-white">Your Library</h1>
          </div>
          <div className="flex items-center gap-4 text-white">
              {!isOfflineMode && <button onClick={() => navigate('/premium')} className="hover:text-white/70 transition-colors"><Sparkles size={24} /></button>}
              <button className="hover:text-white/70 transition-colors"><Search size={24} /></button>
              <button onClick={() => setIsModalOpen(true)} className="hover:text-white/70 transition-colors"><Plus size={26} /></button>
          </div>
      </div>

      {/* Offline Banner in Library */}
      {isOfflineMode && (
         <motion.div 
            initial={{ opacity: 0, y: -10 }}
            animate={{ opacity: 1, y: 0 }}
            className="mb-4 bg-[#2A2A2A] rounded-lg p-3 flex items-center gap-3"
         >
             <div className="bg-[#333] p-2 rounded-full"><WifiOff size={16} /></div>
             <div className="flex flex-col">
                 <span className="text-sm font-bold text-white">You're offline</span>
                 <span className="text-xs text-[#B3B3B3]">Showing only downloaded music.</span>
             </div>
         </motion.div>
      )}

      {/* Filters */}
      <div className="flex items-center gap-2 mb-6 overflow-x-auto no-scrollbar">
          {!isOfflineMode && <FilterChip label="All" />}
          {!isOfflineMode && <FilterChip label="Playlists" />}
          {!isOfflineMode && <FilterChip label="Artists" />}
          <FilterChip label="Downloaded" />
      </div>

      {/* Sort Row */}
      <div className="flex items-center justify-between mb-4">
          <div className="flex items-center gap-1 text-white/90 text-sm">
              <ArrowUpDown size={14} />
              <span className="font-medium">Recents</span>
          </div>
          <div className="p-1">
              <div className="grid grid-cols-2 gap-0.5">
                  <div className="w-1.5 h-1.5 bg-white/50 rounded-[1px]"></div>
                  <div className="w-1.5 h-1.5 bg-white/50 rounded-[1px]"></div>
                  <div className="w-1.5 h-1.5 bg-white/50 rounded-[1px]"></div>
                  <div className="w-1.5 h-1.5 bg-white/50 rounded-[1px]"></div>
              </div>
          </div>
      </div>

      {/* List Content */}
      <motion.div 
        className="flex flex-col gap-2"
        variants={containerVariants}
        initial="hidden"
        animate="visible"
      >

          {/* Liked Songs Pin */}
          {(!isOfflineMode || downloadedLikedSongsCount > 0) && (
              <motion.div 
                variants={itemVariants}
                onClick={() => navigate('/liked')}
                className="flex items-center gap-3 p-2 -mx-2 hover:bg-[#1A1A1A] rounded-md cursor-pointer active:scale-[0.99] transition-all group"
              >
                  <div className="w-[50px] h-[50px] bg-gradient-to-br from-[#333] to-[#666] flex items-center justify-center shrink-0 rounded-[4px]">
                     <Heart size={24} fill="white" className="text-white" />
                  </div>
                  <div className="flex flex-col flex-1 min-w-0">
                      <span className="text-white font-medium text-[15px] truncate group-hover:text-white">Liked Songs</span>
                      <div className="flex items-center gap-1.5 text-[#B3B3B3] text-sm">
                           <Pin size={12} fill="white" className="text-white rotate-45" />
                           <span>Playlist • {isOfflineMode ? downloadedLikedSongsCount : likedSongs.length} songs</span>
                           {isOfflineMode && <CheckCircle2 size={12} className="text-white" />}
                      </div>
                  </div>
              </motion.div>
          )}

          {/* User Playlists */}
          {filteredPlaylists.map(playlist => (
             <motion.div 
                key={playlist.id}
                variants={itemVariants}
                onClick={() => navigate(`/playlist/${playlist.id}`)}
                className="flex items-center gap-3 p-2 -mx-2 hover:bg-[#1A1A1A] rounded-md cursor-pointer active:scale-[0.99] transition-all group"
             >
                <div className="w-[50px] h-[50px] bg-[#333] shrink-0 rounded-[4px] overflow-hidden">
                    {playlist.image && playlist.image[0] ? (
                        <img src={getImageUrl(playlist.image)} alt={playlist.title} className="w-full h-full object-cover" />
                    ) : (
                        <div className="w-full h-full flex items-center justify-center bg-[#282828]">
                            <Music size={24} className="text-white/40" />
                        </div>
                    )}
                </div>
                <div className="flex flex-col flex-1 min-w-0">
                    <span className="text-white font-medium text-[15px] truncate">{playlist.title}</span>
                    <div className="flex items-center gap-1 text-[#B3B3B3] text-sm truncate">
                        <span>Playlist • {playlist.subtitle}</span>
                        {isOfflineMode && <CheckCircle2 size={12} className="text-white" />}
                    </div>
                </div>
             </motion.div>
          ))}

          {isOfflineMode && filteredPlaylists.length === 0 && downloadedLikedSongsCount === 0 && (
              <div className="text-center py-10 text-[#777]">
                  <WifiOff size={40} className="mx-auto mb-4 opacity-50" />
                  <p>No downloaded content found.</p>
                  <p className="text-xs mt-2">Go online to download music.</p>
              </div>
          )}

      </motion.div>

      {isModalOpen && <CreatePlaylistModal onClose={() => setIsModalOpen(false)} />}
    </div>
  );
};

import React, { useEffect, useState } from 'react';
import { useParams, useLocation, useNavigate } from 'react-router-dom';
import { api, getImageUrl } from '../services/api';
import { Artist, Song, Album } from '../types';
import { usePlayerStore } from '../store/playerStore';
import { Play, Pause, CheckCircle2, PlusCircle, ArrowLeft, MoreHorizontal, Disc } from 'lucide-react';
import { motion } from 'framer-motion';

const containerVariants = {
  hidden: { opacity: 0 },
  visible: {
    opacity: 1,
    transition: {
      staggerChildren: 0.1
    }
  }
};

const itemVariants = {
  hidden: { opacity: 0, x: -20 },
  visible: { opacity: 1, x: 0 }
};

export const ArtistDetails: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const location = useLocation();
  const navigate = useNavigate();
  const [artist, setArtist] = useState<Artist | null>(location.state?.artist || null);
  const [songs, setSongs] = useState<Song[]>([]);
  const [albums, setAlbums] = useState<Album[]>([]);
  const [loading, setLoading] = useState(!artist);
  const { playSong, currentSong, isPlaying, toggleLike, likedSongs } = usePlayerStore();

  const [scrollOpacity, setScrollOpacity] = useState(0);

  useEffect(() => {
    const handleScroll = () => {
        const opacity = Math.min(window.scrollY / 200, 1);
        setScrollOpacity(opacity);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  useEffect(() => {
    const fetchData = async () => {
      let currentArtist = artist;

      // 1. Fetch Artist Info if not present
      if (!currentArtist && id) {
        try {
           const results = await api.searchArtists(id);
           if (results.length > 0) {
             currentArtist = results[0];
             setArtist(currentArtist);
           }
        } catch (e) {
           console.error("Failed to fetch artist", e);
        }
      }

      // 2. Fetch Songs and Albums
      if (currentArtist) {
        setLoading(true);
        try {
            const [trackResults, albumResults] = await Promise.all([
                api.searchSongs(currentArtist.name),
                api.searchAlbums(currentArtist.name)
            ]);
            setSongs(trackResults);
            setAlbums(albumResults);
        } catch (e) {
            console.error("Failed to fetch artist details", e);
        } finally {
            setLoading(false);
        }
      } else {
        setLoading(false);
      }
    };

    fetchData();
  }, [id, artist]);

  if (loading) {
     return <div className="flex h-screen w-full items-center justify-center bg-black"><div className="w-8 h-8 border-2 border-white border-t-transparent rounded-full animate-spin"></div></div>;
  }

  if (!artist) {
      return (
          <div className="flex flex-col items-center justify-center h-full gap-4 text-white">
              <span className="text-secondary">Artist not found.</span>
              <button onClick={() => navigate('/search')} className="px-6 py-3 bg-white text-black rounded-full text-sm font-bold">Go to Search</button>
          </div>
      );
  }

  const imageUrl = getImageUrl(artist.image);

  return (
    <div className="min-h-full pb-32 bg-[#121212] text-white relative isolate">

        {/* Sticky Header */}
        <div 
            className="fixed top-0 left-0 right-0 z-40 transition-colors duration-200 flex items-center justify-between px-4 py-3"
            style={{ backgroundColor: `rgba(18, 18, 18, ${scrollOpacity})`, backdropFilter: scrollOpacity > 0.8 ? 'blur(10px)' : 'none' }}
        >
            <button onClick={() => navigate(-1)} className="p-2 rounded-full bg-black/40 hover:bg-black/60 text-white">
                <ArrowLeft size={20} />
            </button>
            <span 
                className="font-bold text-lg transition-opacity duration-300"
                style={{ opacity: scrollOpacity }}
            >
                {artist.name}
            </span>
            <button className="p-2 rounded-full bg-black/40 hover:bg-black/60 text-white">
                <MoreHorizontal size={20} />
            </button>
        </div>

        {/* Hero Image */}
        <div className="relative w-full h-[350px] md:h-[450px] -mt-[64px] z-0">
            <div className="absolute inset-0 bg-gradient-to-b from-transparent via-black/40 to-[#121212] z-10"></div>
            <motion.img 
                initial={{ scale: 1.1 }}
                animate={{ scale: 1 }}
                transition={{ duration: 1 }}
                src={imageUrl} 
                alt={artist.name} 
                className="w-full h-full object-cover object-center" 
            />
            <div className="absolute bottom-0 left-0 p-6 z-20 w-full">
                 <motion.div 
                    initial={{ opacity: 0, x: -20 }}
                    animate={{ opacity: 1, x: 0 }}
                    transition={{ delay: 0.2 }}
                    className="flex items-center gap-2 mb-2"
                 >
                     <CheckCircle2 size={24} className="text-white fill-white bg-white rounded-full border-none" />
                     <span className="text-sm font-medium tracking-wide">Verified Artist</span>
                 </motion.div>
                 <motion.h1 
                    initial={{ opacity: 0, y: 20 }}
                    animate={{ opacity: 1, y: 0 }}
                    transition={{ delay: 0.3 }}
                    className="text-5xl md:text-7xl font-black text-white drop-shadow-xl"
                >
                    {artist.name}
                 </motion.h1>
                 <motion.p 
                    initial={{ opacity: 0 }}
                    animate={{ opacity: 0.8 }}
                    transition={{ delay: 0.4 }}
                    className="text-white/80 mt-2 font-medium"
                 >
                    10,230,129 monthly listeners
                 </motion.p>
            </div>
        </div>

        {/* Action Buttons */}
        <div className="px-4 py-6 flex items-center gap-4 bg-[#121212] relative z-20">
             <motion.button 
                 initial={{ scale: 0 }}
                 animate={{ scale: 1 }}
                 transition={{ type: "spring", delay: 0.5 }}
                 onClick={() => songs.length > 0 && playSong(songs[0], songs)}
                 className="w-14 h-14 bg-white rounded-full flex items-center justify-center hover:scale-105 active:scale-95 transition-transform shadow-lg"
             >
                 {isPlaying && currentSong?.artists?.primary?.[0]?.name === artist.name ? (
                     <Pause size={28} fill="black" className="text-black" />
                 ) : (
                     <Play size={28} fill="black" className="text-black ml-1" />
                 )}
             </motion.button>
             <button className="px-5 py-2 rounded-full border border-white/40 text-sm font-bold hover:border-white transition-colors">
                 Follow
             </button>
        </div>

        {/* Popular Songs */}
        <div className="px-4 pb-8 bg-[#121212] relative z-20">
            <h2 className="text-xl font-bold mb-4">Popular</h2>
            <motion.div 
                className="flex flex-col"
                variants={containerVariants}
                initial="hidden"
                animate="visible"
            >
                {songs.length === 0 ? (
                    <div className="text-secondary italic">No songs found.</div>
                ) : (
                    songs.slice(0, 5).map((song, index) => {
                        const isCurrent = currentSong?.id === song.id;
                        const isSongLiked = likedSongs.some(s => s.id === song.id);

                        return (
                            <motion.div 
                                key={song.id}
                                variants={itemVariants}
                                onClick={() => playSong(song, songs)}
                                className={`flex items-center gap-4 p-3 rounded-md cursor-pointer transition-colors ${isCurrent ? 'bg-white/10' : 'hover:bg-white/5'}`}
                            >
                                <span className={`w-4 text-center text-sm font-mono ${isCurrent ? 'text-white' : 'text-[#B3B3B3]'}`}>
                                    {index + 1}
                                </span>

                                <img src={getImageUrl(song.image)} className="w-10 h-10 rounded object-cover" alt="" />

                                <div className="flex-1 min-w-0">
                                    <div className={`font-medium truncate text-[15px] ${isCurrent ? 'text-white' : 'text-white'}`}>
                                        {song.name}
                                    </div>
                                    <div className="text-xs text-[#B3B3B3] truncate">
                                        {song.downloadUrl?.some(u => u.quality.includes('320')) && (
                                            <span className="bg-[#555] text-white px-1 rounded-[2px] text-[9px] mr-1">E</span>
                                        )}
                                        {song.artists.primary[0]?.name}
                                    </div>
                                </div>

                                <span className="text-xs text-[#B3B3B3] font-mono hidden md:block">
                                    {(parseInt(song.duration) / 60).toFixed(0)}:{(parseInt(song.duration) % 60).toString().padStart(2, '0')}
                                </span>

                                <button 
                                    onClick={(e) => { e.stopPropagation(); toggleLike(song); }}
                                    className={`${isSongLiked ? 'text-white' : 'text-[#B3B3B3] hover:text-white'}`}
                                >
                                    {isSongLiked ? <CheckCircle2 size={18} /> : <PlusCircle size={18} />}
                                </button>
                            </motion.div>
                        );
                    })
                )}
            </motion.div>
        </div>

        {/* Albums Section */}
        {albums.length > 0 && (
            <div className="px-4 pb-8 bg-[#121212] relative z-20">
                <h2 className="text-xl font-bold mb-4">Discography</h2>
                <div className="flex overflow-x-auto gap-4 no-scrollbar pb-2">
                    {albums.map((album) => (
                        <motion.div 
                            key={album.id} 
                            whileHover={{ y: -5 }}
                            className="w-[150px] shrink-0 cursor-pointer group"
                            onClick={() => navigate(`/album/${album.id}`)}
                        >
                            <div className="w-full aspect-square mb-2 relative">
                                <img src={getImageUrl(album.image)} alt={album.name} className="w-full h-full object-cover rounded-md shadow-md" />
                            </div>
                            <h3 className="text-sm font-bold text-white truncate group-hover:underline">{album.name}</h3>
                            <p className="text-xs text-[#B3B3B3]">{album.year} • Album</p>
                        </motion.div>
                    ))}
                </div>
            </div>
        )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { usePlayerStore } from '../store/playerStore';
import { authService } from '../services/auth';
import { getImageUrl, api } from '../services/api';
import { Play, Pause, Clock3, MoreHorizontal, Trash2, Music, ArrowLeft, Search, Heart, Share2, Check, User } from 'lucide-react';
import { Song, UserPlaylist } from '../types';
import { motion } from 'framer-motion';

const listVariants = {
  hidden: { opacity: 0 },
  visible: {
    opacity: 1,
    transition: {
      staggerChildren: 0.05,
      delayChildren: 0.2
    }
  }
};

const itemVariants = {
  hidden: { opacity: 0, x: -10 },
  visible: { opacity: 1, x: 0 }
};

export const PlaylistDetails: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const { userPlaylists, playSong, currentSong, isPlaying, removePlaylist, addSongToPlaylist, importPlaylist } = usePlayerStore();

  const [searchQuery, setSearchQuery] = useState('');
  const [searchResults, setSearchResults] = useState<Song[]>([]);
  const [isSearching, setIsSearching] = useState(false);

  const [viewPlaylist, setViewPlaylist] = useState<UserPlaylist | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [isScrolled, setIsScrolled] = useState(false);
  const [shareFeedback, setShareFeedback] = useState(false);

  const isMyPlaylist = userPlaylists.some(p => p.id === id);

  useEffect(() => {
    const main = document.querySelector('main');
    const handleScroll = () => {
        if (main) setIsScrolled(main.scrollTop > 200);
    };
    main?.addEventListener('scroll', handleScroll);
    return () => main?.removeEventListener('scroll', handleScroll);
  }, []);

  useEffect(() => {
      const loadPlaylist = async () => {
          setIsLoading(true);
          const localPlaylist = userPlaylists.find(p => p.id === id);
          if (localPlaylist) {
              setViewPlaylist(localPlaylist);
              setIsLoading(false);
              return;
          }
          if (id) {
              const publicPlaylist = await authService.getPublicPlaylist(id);
              if (publicPlaylist) {
                  setViewPlaylist(publicPlaylist);
              }
          }
          setIsLoading(false);
      };
      loadPlaylist();
  }, [id, userPlaylists]);

  // Debounced Search for "Add Songs"
  useEffect(() => {
    const timer = setTimeout(async () => {
      if (searchQuery.trim()) {
        setIsSearching(true);
        try {
           const songs = await api.searchSongs(searchQuery);
           setSearchResults(songs.slice(0, 5));
        } catch (e) { console.error(e); } 
        finally { setIsSearching(false); }
      } else {
        setSearchResults([]);
      }
    }, 500); 
    return () => clearTimeout(timer);
  }, [searchQuery]);


  if (isLoading) {
      return <div className="flex h-full w-full items-center justify-center bg-[#121212]"><div className="w-8 h-8 border-2 border-white border-t-transparent rounded-full animate-spin"></div></div>;
  }

  if (!viewPlaylist) {
      return (
          <div className="flex flex-col items-center justify-center h-full text-white">
              <h2 className="text-2xl font-bold mb-4">Playlist not found</h2>
              <button onClick={() => navigate('/library')} className="px-6 py-2 bg-white text-black rounded-full font-bold">Back to Library</button>
          </div>
      );
  }

  const handleDelete = () => {
      if (window.confirm("Are you sure you want to delete this playlist?")) {
          removePlaylist(viewPlaylist.id);
          navigate('/library');
      }
  };

  const handleImport = () => {
      importPlaylist(viewPlaylist);
      alert('Playlist added to your library!');
  };

  const handleShare = () => {
      const url = window.location.href;
      navigator.clipboard.writeText(url).then(() => {
          setShareFeedback(true);
          setTimeout(() => setShareFeedback(false), 2000);
      }).catch(err => console.error("Failed to copy", err));
  };

  const handleAddSong = (song: Song) => {
      addSongToPlaylist(viewPlaylist.id, song);
      setSearchQuery(''); 
  };

  const imageUrl = getImageUrl(viewPlaylist.image);

  // Calculate duration
  const totalDurationSeconds = viewPlaylist.songs.reduce((acc, curr) => acc + (parseInt(curr.duration) || 0), 0);
  const totalDurationHours = Math.floor(totalDurationSeconds / 3600);
  const totalDurationMinutes = Math.floor((totalDurationSeconds % 3600) / 60);

  return (
    <div className="min-h-full pb-32 bg-[#121212] relative isolate">
      {/* Background Gradient */}
      <div className="absolute top-0 left-0 right-0 h-[400px] bg-gradient-to-b from-[#404040] via-[#282828] to-[#121212] -z-10 transition-colors duration-700"></div>

      {/* Sticky Header */}
      <div className={`sticky top-0 z-50 h-[64px] px-6 flex items-center justify-between transition-all duration-300 ${isScrolled ? 'bg-[#282828] shadow-lg border-b border-white/5' : 'bg-transparent border-transparent'}`}>
          <div className="flex items-center gap-4">
              <button onClick={() => navigate(-1)} className="w-8 h-8 rounded-full bg-black/20 hover:bg-black/40 flex items-center justify-center text-white transition-colors">
                 <ArrowLeft size={20} />
              </button>
              <span className={`font-bold text-lg text-white transition-opacity duration-300 ${isScrolled ? 'opacity-100' : 'opacity-0'}`}>
                  {viewPlaylist.title}
              </span>
              {isScrolled && viewPlaylist.songs.length > 0 && (
                   <button 
                    onClick={() => playSong(viewPlaylist.songs[0], viewPlaylist.songs)}
                    className="w-10 h-10 rounded-full bg-white flex items-center justify-center hover:scale-105 transition-transform text-black shadow-md"
                   >
                       {isPlaying && viewPlaylist.songs.some(s => s.id === currentSong?.id) ? <Pause size={20} fill="black" /> : <Play size={20} fill="black" className="ml-0.5" />}
                   </button>
              )}
          </div>

          <div className="flex items-center gap-3">
             <button 
                onClick={handleShare}
                className={`flex items-center gap-2 px-3 py-1.5 rounded-full text-xs font-bold border transition-all ${shareFeedback ? 'bg-white border-white text-black' : 'bg-black/20 hover:bg-white/10 text-white border-white/10'}`}
             >
                 {shareFeedback ? <Check size={14} strokeWidth={3} /> : <Share2 size={14} />}
                 <span className="hidden sm:block">{shareFeedback ? 'Copied' : 'Share'}</span>
             </button>
            {isMyPlaylist ? (
                <button onClick={handleDelete} className="w-9 h-9 rounded-full bg-black/20 hover:bg-red-500/20 hover:text-red-500 flex items-center justify-center text-white/70 transition-colors">
