import React, { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { authService } from '../services/auth';
import { usePlayerStore } from '../store/playerStore';
import { ArrowLeft, Loader2 } from 'lucide-react';

export const Signup: React.FC = () => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [name, setName] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const navigate = useNavigate();
  const { loginUser } = usePlayerStore();

  const handleSignup = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError('');

    try {
      const user = await authService.signup(name, email.toLowerCase().trim(), password);
      loginUser(user);
      navigate('/');
    } catch (err: any) {
      setError(err.message || 'Signup failed. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  const handleGoogleSignup = async () => {
      setLoading(true);
      setError('');
      try {
          const user = await authService.loginWithGoogle();
          loginUser(user);
          navigate('/');
      } catch (err: any) {
          setError(err.message || 'Google Signup failed.');
          setLoading(false);
      }
  };

  return (
    <div className="min-h-screen bg-black text-white flex flex-col items-center justify-center p-4">

      <div className="w-full max-w-sm flex flex-col gap-6">
        {/* Header */}
        <div className="flex flex-col items-center gap-4 mb-2">
           <img 
              src="https://static.vecteezy.com/system/resources/previews/065/386/690/non_2x/spotify-white-logo-icon-spotify-app-editable-svg-transparent-background-premium-social-media-design-for-digital-download-free-png.png" 
              alt="Spotify" 
              className="h-10 w-auto" 
           />
           <h1 className="text-3xl font-bold text-center tracking-tighter">Sign up to start listening</h1>
        </div>

        {error && (
             <div className="bg-red-500/10 border border-red-500/50 text-red-500 p-3 rounded text-sm text-center">
               {error}
             </div>
        )}

        {/* Social Signup */}
        <div className="flex flex-col gap-2">
            <button 
                onClick={handleGoogleSignup}
                disabled={loading}
                className="flex items-center justify-center gap-4 w-full bg-transparent border border-[#555] hover:border-white text-white font-bold py-3 rounded-full transition-all"
            >
