import React, { useState, useRef, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { usePlayerStore } from '../store/playerStore';
import { uploadToCloudinary } from '../services/api';
import { ArrowLeft, Camera, Loader2, Save, LogOut, Cloud, SignalHigh, SignalMedium, SignalLow, Music2, Users, ChevronRight, Mail, Shield, RotateCcw, Youtube, Library, Globe, Layers, DownloadCloud } from 'lucide-react';
import { motion } from 'framer-motion';

export const Profile: React.FC = () => {
  const { currentUser, updateUserProfile, logoutUser, streamingQuality, setStreamingQuality, favoriteArtists, musicSource, setMusicSource } = usePlayerStore();
  const navigate = useNavigate();

  const [name, setName] = useState('');
  const [imagePreview, setImagePreview] = useState<string | null>(null);
  const [imageFile, setImageFile] = useState<File | null>(null);
  const [loading, setLoading] = useState(false);
  const [scrollOpacity, setScrollOpacity] = useState(0);

  // App Update State
  const [checkingUpdate, setCheckingUpdate] = useState(false);
  const [updateAvailable, setUpdateAvailable] = useState(false);
  const currentVersion = "2.4.0";

  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (currentUser) {
      setName(currentUser.name);
      setImagePreview(currentUser.image || null);
    } else {
      navigate('/login');
    }
  }, [currentUser, navigate]);

  useEffect(() => {
    const handleScroll = () => {
        const opacity = Math.min(window.scrollY / 200, 1);
        setScrollOpacity(opacity);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const handleImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      setImageFile(file);
      setImagePreview(URL.createObjectURL(file));
    }
  };

  const handleSave = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!name.trim()) return;

    setLoading(true);
    try {
      let imageUrl = imagePreview;
      if (imageFile) {
        imageUrl = await uploadToCloudinary(imageFile);
      }
      updateUserProfile(name, imageUrl || undefined);
      await new Promise(r => setTimeout(r, 800)); // UX delay
      alert('Profile updated');
    } catch (error) {
      console.error("Failed to update profile", error);
    } finally {
      setLoading(false);
    }
  };

  const handleLogout = () => {
    if(window.confirm('Are you sure you want to log out?')) {
        logoutUser();
        navigate('/');
    }
  };

  const handleCheckUpdate = () => {
      setCheckingUpdate(true);
      setTimeout(() => {
          setCheckingUpdate(false);
          // Simulate 50/50 chance of update for demo
          const isAvailable = Math.random() > 0.5;
          setUpdateAvailable(isAvailable);
          if (!isAvailable) {
              alert("You are already on the latest version.");
          }
      }, 2000);
  };

  const handleUpdate = () => {
      if (confirm("Install update and restart?")) {
          window.location.reload();
      }
  };

  if (!currentUser) return null;

  return (
    <div className="min-h-full bg-[#121212] text-white pb-32 relative isolate">

      {/* Background Gradient */}
      <div className="absolute top-0 left-0 right-0 h-[400px] bg-gradient-to-b from-[#535353] to-[#121212] -z-10" />

      {/* Sticky Header */}
      <div 
        className="sticky top-0 z-40 px-6 py-4 flex items-center justify-between transition-colors duration-200"
        style={{ backgroundColor: `rgba(18, 18, 18, ${scrollOpacity})` }}
      >
          <button 
              onClick={() => navigate(-1)} 
              className="w-8 h-8 rounded-full bg-black/40 hover:bg-black/60 flex items-center justify-center text-white transition-colors"
          >
              <ArrowLeft size={20} />
          </button>
          <span 
            className="font-bold text-sm opacity-0 transition-opacity duration-300"
            style={{ opacity: scrollOpacity }}
          >
            {name}
          </span>
          <div className="flex items-center gap-2">
            <button 
                onClick={() => window.location.reload()}
                className="w-8 h-8 rounded-full bg-black/40 hover:bg-black/60 flex items-center justify-center text-white transition-colors"
                title="Restart App"
            >
                <RotateCcw size={16} />
            </button>
            <button 
                onClick={handleLogout}
                className="w-8 h-8 rounded-full bg-black/40 hover:bg-black/60 flex items-center justify-center text-white transition-colors"
                title="Log Out"
            >
                <LogOut size={16} />
            </button>
          </div>
      </div>

      <div className="max-w-3xl mx-auto px-6 flex flex-col gap-8 -mt-2">

          {/* Hero Profile Section */}
          <div className="flex flex-col items-center gap-6 animate-in slide-in-from-bottom-4 duration-500">
              <div 
                onClick={() => fileInputRef.current?.click()}
                className="relative w-48 h-48 md:w-56 md:h-56 rounded-full shadow-[0_8px_40px_rgba(0,0,0,0.5)] group cursor-pointer"
              >
                 {imagePreview ? (
                    <img src={imagePreview} alt="Profile" className="w-full h-full object-cover rounded-full" />
                 ) : (
                    <div className="w-full h-full rounded-full bg-[#282828] flex items-center justify-center text-6xl font-bold text-white/20">
                        {name.charAt(0).toUpperCase()}
                    </div>
                 )}

                 <div className="absolute inset-0 bg-black/50 rounded-full flex flex-col items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity backdrop-blur-[2px]">
                     <Camera size={32} className="text-white mb-2" />
                     <span className="text-xs font-bold uppercase tracking-widest">Edit Photo</span>
                 </div>
                 <div className="absolute bottom-2 right-4 bg-white text-black p-2 rounded-full border-4 border-[#121212]">
                    <Cloud size={16} />
                 </div>
              </div>
              <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={handleImageChange} />

              <div className="flex flex-col items-center gap-2 w-full">
                  <input 
                    type="text" 
                    value={name}
                    onChange={(e) => setName(e.target.value)}
                    className="bg-transparent text-center text-4xl md:text-5xl font-black text-white outline-none border-b border-transparent focus:border-white/20 pb-1 w-full max-w-md transition-all placeholder-white/20"
                    placeholder="Name"
                  />
                  <div className="flex items-center gap-6 text-sm font-bold text-white/70 mt-2">
                      <div className="flex flex-col items-center">
                          <span className="text-white">12</span>
                          <span className="text-[10px] uppercase tracking-wider">Playlists</span>
                      </div>
                      <div className="flex flex-col items-center">
                          <span className="text-white">148</span>
                          <span className="text-[10px] uppercase tracking-wider">Followers</span>
                      </div>
                      <div className="flex flex-col items-center">
                          <span className="text-white">23</span>
                          <span className="text-[10px] uppercase tracking-wider">Following</span>
                      </div>
                  </div>
              </div>
          </div>

          <form onSubmit={handleSave} className="flex flex-col gap-6 mt-4">

              {/* Account Card */}
              <div className="bg-[#181818] p-5 rounded-lg">
                   <h3 className="text-lg font-bold mb-4 flex items-center gap-2">
                      <Shield size={20} className="text-white"/> Account
                   </h3>
                   <div className="flex items-center gap-4 text-sm">
                      <div className="p-3 bg-[#2A2A2A] rounded-full text-[#B3B3B3]">
                          <Mail size={20} />
                      </div>
                      <div className="flex flex-col flex-1">
                          <span className="text-xs text-[#B3B3B3] font-bold uppercase tracking-wider">Email</span>
                          <span className="text-white/80 font-medium">{currentUser.email}</span>
                      </div>
                      <span className="px-3 py-1 bg-[#2A2A2A] rounded-full text-[10px] font-bold text-[#B3B3B3]">PRIVATE</span>
                   </div>
              </div>

              {/* Taste Profile */}
              <div 
                  onClick={() => navigate('/artists/select')}
                  className="bg-[#181818] p-5 rounded-lg cursor-pointer hover:bg-[#202020] transition-colors group"
              >
                   <div className="flex items-center justify-between mb-2">
                        <h3 className="text-lg font-bold flex items-center gap-2">
                            <Users size={20} className="text-white"/> Taste Profile
                        </h3>
                        <ChevronRight className="text-[#555] group-hover:text-white transition-colors" />
                   </div>
                   <p className="text-sm text-[#B3B3B3] mb-4">Manage the artists you follow to improve recommendations.</p>

                   <div className="flex items-center gap-2 overflow-hidden">
                       {favoriteArtists.slice(0, 5).map((artist, i) => (
                           <div key={artist.id} className="w-10 h-10 rounded-full bg-[#333] overflow-hidden border border-black relative" style={{ zIndex: 5 - i }}>
                               <img src={artist.image[0]?.url} className="w-full h-full object-cover" alt=""/>
                           </div>
                       ))}
                       {favoriteArtists.length > 5 && (
                           <div className="w-10 h-10 rounded-full bg-[#2A2A2A] flex items-center justify-center text-xs font-bold text-white border border-black z-0">
                               +{favoriteArtists.length - 5}
                           </div>
                       )}
                       {favoriteArtists.length === 0 && <span className="text-sm font-bold text-white">Select Artists</span>}
                   </div>
              </div>

               {/* Music Source Selection */}
               <div className="bg-[#181818] p-5 rounded-lg">
                   <h3 className="text-lg font-bold mb-4 flex items-center gap-2">
                      <Globe size={20} className="text-white"/> Music Source
                   </h3>
                   <div className="flex flex-col gap-2">
                      {[
                          { val: 'both', label: 'Hybrid (Recommended)', sub: 'Results from both sources', Icon: Layers },
                          { val: 'youtube', label: 'YouTube Music', sub: 'Extensive library from YT', Icon: Youtube },
                          { val: 'local', label: 'Local Library', sub: 'High quality official tracks', Icon: Library },
                      ].map((opt) => (
                          <button
                            key={opt.val}
                            type="button"
                            onClick={() => setMusicSource(opt.val as any)}
                            className={`flex items-center p-3 rounded-md transition-all ${
                                musicSource === opt.val 
                                ? 'bg-[#2A2A2A] ring-1 ring-white' 
                                : 'hover:bg-[#2A2A2A]/50'
                            }`}
                          >
                              <div className={`p-2 rounded-full mr-4 ${musicSource === opt.val ? 'text-white' : 'text-[#555]'}`}>
                                  <opt.Icon size={20} />
                              </div>
                              <div className="flex flex-col items-start flex-1">
                                  <span className={`text-sm font-bold ${musicSource === opt.val ? 'text-white' : 'text-white/70'}`}>{opt.label}</span>
                                  <span className="text-xs text-[#555]">{opt.sub}</span>
                              </div>
                              {musicSource === opt.val && <div className="w-3 h-3 bg-white rounded-full shadow-[0_0_10px_white]"></div>}
                          </button>
                      ))}
                   </div>
              </div>

              {/* Audio Quality */}
              <div className="bg-[#181818] p-5 rounded-lg">
                   <h3 className="text-lg font-bold mb-4 flex items-center gap-2">
                      <Music2 size={20} className="text-white"/> Audio Quality
                   </h3>
                   <div className="flex flex-col gap-2">
                      {[
                          { val: 'low', label: 'Low (48kbps)', sub: 'Best for saving data', Icon: SignalLow },
                          { val: 'normal', label: 'Normal (96kbps)', sub: 'Standard balance', Icon: SignalMedium },
                          { val: 'high', label: 'High (320kbps)', sub: 'Best listening experience', Icon: SignalHigh },
                      ].map((opt) => (
                          <button
                            key={opt.val}
                            type="button"
                            onClick={() => setStreamingQuality(opt.val as any)}
                            className={`flex items-center p-3 rounded-md transition-all ${
                                streamingQuality === opt.val 
                                ? 'bg-[#2A2A2A] ring-1 ring-white' 
                                : 'hover:bg-[#2A2A2A]/50'
                            }`}
                          >
                              <div className={`p-2 rounded-full mr-4 ${streamingQuality === opt.val ? 'text-white' : 'text-[#555]'}`}>
                                  <opt.Icon size={20} />
                              </div>
                              <div className="flex flex-col items-start flex-1">
                                  <span className={`text-sm font-bold ${streamingQuality === opt.val ? 'text-white' : 'text-white/70'}`}>{opt.label}</span>
                                  <span className="text-xs text-[#555]">{opt.sub}</span>
                              </div>
                              {streamingQuality === opt.val && <div className="w-3 h-3 bg-white rounded-full shadow-[0_0_10px_white]"></div>}
                          </button>
                      ))}
                   </div>
              </div>

              {/* App Updates Section */}
              <div className="bg-[#181818] p-5 rounded-lg">
                   <h3 className="text-lg font-bold mb-4 flex items-center gap-2">
                      <DownloadCloud size={20} className="text-white"/> App Updates
                   </h3>
                   <div className="flex items-center justify-between bg-[#2A2A2A] p-4 rounded-md">
                        <div className="flex flex-col gap-1">
                            <span className="text-white font-bold text-sm">Version {currentVersion}</span>
                            <span className={`text-xs ${updateAvailable ? 'text-white' : 'text-[#B3B3B3]'}`}>
                                {updateAvailable ? '✨ New version 2.5.0 available' : 'You are up to date'}
                            </span>
                        </div>
                        <button 
                            type="button"
                            onClick={updateAvailable ? handleUpdate : handleCheckUpdate}
                            disabled={checkingUpdate}
                            className={`px-4 py-2 rounded-full font-bold text-xs md:text-sm transition-all flex items-center gap-2 ${
                                updateAvailable 
                                ? 'bg-white text-black hover:scale-105 shadow-lg shadow-white/20' 
                                : 'bg-white/10 text-white hover:bg-white/20'
                            }`}
                        >
                            {checkingUpdate ? (
                                <><Loader2 size={14} className="animate-spin" /> Checking...</>
                            ) : updateAvailable ? (
                                'Update Now'
                            ) : (
                                'Check for Updates'
                            )}
                        </button>
                   </div>
                   {updateAvailable && (
                       <div className="mt-4 text-xs text-[#B3B3B3] bg-[#222] p-3 rounded-md animate-in fade-in slide-in-from-top-2">
                           <p className="font-bold text-white mb-1">What's New in 2.5.0:</p>
                           <ul className="list-disc pl-4 space-y-1">
                               <li>Improved audio engine for cleaner bass</li>
                               <li>New "Sleep Timer" feature in player</li>
                               <li>Bug fixes and performance improvements</li>
                           </ul>
                       </div>
                   )}
              </div>

              <div className="flex justify-center pt-4 pb-8">
                  <button 
                    type="submit" 
                    disabled={loading}
                    className="bg-white text-black font-bold py-3.5 px-12 rounded-full hover:scale-105 active:scale-95 transition-all flex items-center gap-2 shadow-[0_0_20px_rgba(255,255,255,0.1)]"
                  >
                     {loading ? <Loader2 size={20} className="animate-spin" /> : 'Save Changes'}
                  </button>
              </div>

          </form>

      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { usePlayerStore } from '../store/playerStore';
import { X, Send, PlayCircle, StopCircle, Music, Radio, ChevronDown } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';

export const ChatWindow: React.FC = () => {
  const { activeChatFriendId, friends, openChat, sendMessage, partySession, startParty, stopParty, currentUser } = usePlayerStore();
  const [text, setText] = useState('');
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const friend = friends.find(f => f.id === activeChatFriendId);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [friend?.chatHistory, activeChatFriendId]);

  if (!activeChatFriendId || !friend || !currentUser) return null;

  const handleSend = (e: React.FormEvent) => {
    e.preventDefault();
    if (text.trim()) {
        sendMessage(friend.id, text);
        setText('');
    }
  };

  const isHostingParty = partySession?.hostId === 'me' && partySession.isActive;

  const formatTime = (ts: number) => {
      return new Date(ts).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
  };

  return (
    <motion.div 
        initial={{ y: 20, opacity: 0, scale: 0.95 }}
        animate={{ y: 0, opacity: 1, scale: 1 }}
        exit={{ y: 20, opacity: 0 }}
        className="fixed bottom-24 right-4 w-[360px] h-[500px] bg-[#121212] rounded-2xl border border-[#282828] shadow-[0_8px_30px_rgba(0,0,0,0.5)] flex flex-col z-[100] overflow-hidden font-sans"
    >

        {/* Header */}
        <div className="bg-[#181818]/95 backdrop-blur-md p-3 flex items-center justify-between border-b border-[#282828]">
            <div className="flex items-center gap-3">
                <div className="relative">
                    <img src={friend.image || `https://ui-avatars.com/api/?name=${friend.name}&background=1DB954&color=fff`} className="w-10 h-10 rounded-full object-cover shadow-md" alt="" />
                    {friend.status === 'listening' ? (
                        <div className="absolute -bottom-0.5 -right-0.5 w-3.5 h-3.5 bg-white rounded-full border-2 border-[#121212] flex items-center justify-center">
                            <Music size={8} fill="black" className="text-black" />
                        </div>
                    ) : friend.status === 'online' ? (
                        <div className="absolute -bottom-0.5 -right-0.5 w-3.5 h-3.5 bg-green-500 rounded-full border-2 border-[#121212]"></div>
                    ) : null}
                </div>
                <div className="flex flex-col">
                    <span className="text-white font-bold text-sm leading-tight">{friend.name}</span>
                    {friend.status === 'listening' && friend.currentSong ? (
                        <span className="text-[11px] text-white flex items-center gap-1 font-medium truncate max-w-[150px]">
                            Listening to {friend.currentSong.name}
                        </span>
                    ) : (
                        <span className="text-[11px] text-[#777] font-medium">
                            {friend.status === 'online' ? 'Active Now' : 'Offline'}
                        </span>
                    )}
                </div>
            </div>
            <div className="flex items-center gap-1">
                 <button 
                    onClick={isHostingParty ? stopParty : startParty}
                    className={`p-2 rounded-full transition-all ${isHostingParty ? 'text-white bg-white/10' : 'text-[#B3B3B3] hover:text-white hover:bg-[#282828]'}`}
                    title="Listen Together"
                >
                    <Radio size={20} className={isHostingParty ? "animate-pulse" : ""} />
                 </button>
                 <button onClick={() => openChat(null)} className="p-2 text-[#B3B3B3] hover:text-white hover:bg-[#282828] rounded-full transition-colors">
                    <ChevronDown size={20} />
                </button>
            </div>
        </div>

        {/* Messages Area */}
        <div className="flex-1 overflow-y-auto p-4 flex flex-col gap-2 bg-[#000000] bg-opacity-40">
             <div className="text-[10px] text-center text-[#444] my-2 uppercase tracking-widest font-bold">
                 Encrypted Chat
             </div>

             {friend.chatHistory.map((msg, i) => {
                 const isMe = msg.senderId === currentUser.email;
                 const isConsecutive = i > 0 && friend.chatHistory[i-1].senderId === msg.senderId;

                 return (
                     <div key={msg.id} className={`flex flex-col ${isMe ? 'items-end' : 'items-start'} ${isConsecutive ? 'mt-0.5' : 'mt-2'}`}>
                         <div 
                            className={`max-w-[75%] px-3.5 py-2 text-[13px] shadow-sm leading-relaxed relative group ${
                                isMe 
                                ? 'bg-white text-black rounded-2xl rounded-tr-sm' 
                                : 'bg-[#2A2A2A] text-white rounded-2xl rounded-tl-sm'
                            }`}
                         >
                             {msg.text}
                             <div className={`text-[9px] mt-1 opacity-60 text-right ${isMe ? 'text-black' : 'text-gray-400'}`}>
                                 {formatTime(msg.timestamp)}
                             </div>
                         </div>
                     </div>
                 );
             })}
             <div ref={messagesEndRef} />
        </div>

        {/* Input Area */}
        <form onSubmit={handleSend} className="p-3 bg-[#181818] border-t border-[#282828] flex items-center gap-2">
            <input 
                value={text}
                onChange={(e) => setText(e.target.value)}
                placeholder="Type a message..."
                className="flex-1 bg-[#282828] rounded-full px-4 py-2.5 text-sm text-white focus:outline-none focus:ring-1 focus:ring-[#555] transition-all placeholder-[#555]"
            />
            <button 
                type="submit" 
                disabled={!text.trim()} 
                className="p-2.5 bg-white text-black rounded-full hover:scale-105 active:scale-95 disabled:opacity-50 disabled:scale-100 transition-all shadow-lg"
            >
                <Send size={18} fill="black" className="ml-0.5" />
            </button>
        </form>
    </motion.div>
  );
};

import React from 'react';
import { usePlayerStore } from '../store/playerStore';
import { motion, AnimatePresence } from 'framer-motion';
import { Check, ArrowDown } from 'lucide-react';
import { getImageUrl } from '../services/api';

export const DownloadProgress: React.FC = () => {
  const { activeDownload, downloadProgress } = usePlayerStore();

  if (!activeDownload) return null;

  const isComplete = downloadProgress >= 100;

  // Calculate circumference for circle progress
  const radius = 24;
  const circumference = 2 * Math.PI * radius;
  const strokeDashoffset = circumference - (downloadProgress / 100) * circumference;

  return (
    <AnimatePresence>
        <div className="fixed bottom-24 md:bottom-28 left-0 right-0 z-[200] flex justify-center pointer-events-none">
            <motion.div
                initial={{ y: 50, opacity: 0, scale: 0.9 }}
                animate={{ y: 0, opacity: 1, scale: 1 }}
                exit={{ y: 50, opacity: 0, scale: 0.9 }}
                transition={{ type: "spring", stiffness: 300, damping: 25 }}
                className="bg-[#121212]/90 backdrop-blur-xl border border-white/10 rounded-full pl-2 pr-6 py-2 shadow-2xl flex items-center gap-4 min-w-[280px]"
            >
                {/* Album Art & Progress Circle */}
                <div className="relative w-12 h-12 shrink-0">
                    {/* Background Circle */}
                    <svg className="absolute inset-0 w-full h-full -rotate-90">
                        <circle
                            cx="24"
                            cy="24"
                            r={radius}
                            fill="transparent"
                            stroke="#333"
                            strokeWidth="3"
                        />
                        <motion.circle
                            cx="24"
                            cy="24"
                            r={radius}
                            fill="transparent"
                            stroke={isComplete ? "white" : "white"}
                            strokeWidth="3"
                            strokeDasharray={circumference}
                            animate={{ strokeDashoffset }}
                            transition={{ duration: 0.2 }}
                            strokeLinecap="round"
                        />
                    </svg>

                    {/* Image or Checkmark */}
                    <div className="absolute inset-[6px] rounded-full overflow-hidden bg-[#222] flex items-center justify-center">
                        <AnimatePresence mode="wait">
                            {isComplete ? (
                                <motion.div
                                    key="check"
                                    initial={{ scale: 0 }}
                                    animate={{ scale: 1 }}
                                    className="w-full h-full bg-white flex items-center justify-center"
                                >
                                    <Check size={20} className="text-black" strokeWidth={3} />
                                </motion.div>
                            ) : (
                                <motion.img
                                    key="img"
                                    src={getImageUrl(activeDownload.image)}
                                    alt=""
                                    className="w-full h-full object-cover opacity-80"
                                    initial={{ opacity: 0 }}
                                    animate={{ opacity: 0.8 }}
                                />
                            )}
                        </AnimatePresence>
                    </div>

                    {/* Loading Icon Overlay */}
                    {!isComplete && (
                        <div className="absolute inset-0 flex items-center justify-center">
                            <ArrowDown size={14} className="text-white drop-shadow-md animate-bounce" />
                        </div>
                    )}
                </div>

                {/* Text Info */}
                <div className="flex flex-col flex-1 min-w-0">
                    <motion.span 
                        layout
                        className="text-white font-bold text-sm truncate"
                    >
                        {isComplete ? "Downloaded" : "Downloading..."}
                    </motion.span>
                    <motion.span 
                        layout
                        className="text-[#B3B3B3] text-xs truncate"
                    >
                        {isComplete ? activeDownload.name : `${Math.round(downloadProgress)}% • ${activeDownload.name}`}
                    </motion.span>
                </div>

            </motion.div>
        </div>
    </AnimatePresence>
  );
};

